import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        A = [int(next(it)) for _ in range(N)]
        if A[-1] != 1:
            out_lines.append('-1')
            continue
        ans = []
        last = 0
        for i in range(1, N+1):
            if A[i-1] == 1:
                for j in range(i, last, -1):
                    ans.append(str(j))
                last = i
        out_lines.append(' '.join(ans))
    sys.stdout.write('\n'.join(out_lines))
if __name__ == "__main__":
    solve()

