const fs = require('fs');
const input = fs.readFileSync(0,'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let out = [];
for(let t=0;t<T;t++){
  const N = input[idx++];
  const A = input.slice(idx, idx+N); idx+=N;
  if(A[N-1]!==1){ out.push('-1'); continue; }
  let ans = [];
  let last = 0;
  for(let i=1;i<=N;i++){
    if(A[i-1]===1){
      for(let j=i;j>last;j--) ans.push(j);
      last = i;
    }
  }
  out.push(ans.join(' '));
}
